// Handles Fluent Forms and generic flat JSON webhook payloads.
// Fluent Forms wraps fields inside a 'data' object; generic providers use top-level keys.

const raw  = $input.first().json;
const body = raw.body || raw; // some n8n webhook configs nest the payload inside .body

let lead_name = '', lead_email = '', lead_phone = '', lead_message = '', lead_source = '';

if (body.data && typeof body.data === 'object') {
  // Fluent Forms shape
  const d = body.data;
  if (d.names && typeof d.names === 'object') {
    lead_name = [d.names.first_name, d.names.last_name].filter(Boolean).join(' ').trim();
  } else {
    lead_name = (d.full_name || d.name || [d.first_name, d.last_name].filter(Boolean).join(' ') || '').trim();
  }
  lead_email   = (d.email || '').trim();
  lead_phone   = (d.phone || d.phone_number || d.mobile || d.telephone || '').trim();
  lead_message = (d.message || d.notes || d.how_can_we_help || d.comments || d.description || '').trim();
  lead_source  = body.form_title ? 'Form: ' + body.form_title : (body.form_id ? 'Form ID ' + body.form_id : 'Fluent Forms');
} else {
  // Generic flat JSON — Typeform, Gravity Forms, Zapier-style webhooks, etc.
  lead_name    = (body.full_name || body.name || [body.first_name, body.last_name].filter(Boolean).join(' ') || '').trim();
  lead_email   = (body.email || '').trim();
  lead_phone   = (body.phone || body.phone_number || body.mobile || body.telephone || '').trim();
  lead_message = (body.message || body.notes || body.comments || body.how_can_we_help || body.description || '').trim();
  lead_source  = (body.source || body.form_name || body.form_title || body.referrer || 'Website form').trim();
}

const has_email = lead_email.includes('@');
const has_phone = lead_phone.replace(/\D/g, '').length >= 7;

return [{ json: {
  lead_name:     lead_name || 'Prospect',
  lead_email,
  lead_phone,
  lead_message,
  lead_source,
  is_valid_lead: has_email || has_phone,
  received_at:   new Date().toISOString(),
} }];

// Round-robin attorney assignment.
// DUTY_ATTORNEYS variable format: Name|email|phone,Name2|email2|phone2
// Each attorney entry uses pipe ( | ) as the field separator.
// Multiple attorneys are separated by commas.
//
// staticData persists the rotation index across executions automatically.
// It resets only if you re-save this workflow with a code change.

const raw = ($vars.DUTY_ATTORNEYS || '').trim();
if (!raw) {
  throw new Error('Speed-to-Lead Router: DUTY_ATTORNEYS variable is not set. Go to project → Variables tab and add at least one attorney in the format: Name|email|phone');
}

const attorneys = raw.split(',').map(entry => {
  const parts = entry.trim().split('|').map(p => p.trim());
  return { name: parts[0] || '', email: parts[1] || '', phone: parts[2] || '' };
}).filter(a => a.name || a.email);

if (attorneys.length === 0) {
  throw new Error('Speed-to-Lead Router: DUTY_ATTORNEYS is set but no valid entries were parsed. Expected format: Name|email|phone,Name2|email2|phone2');
}

const data    = $getWorkflowStaticData('global');
const idx     = typeof data.round_robin_index === 'number' ? data.round_robin_index : 0;
const safeIdx = idx % attorneys.length;
const attorney = attorneys[safeIdx];

data.round_robin_index = (safeIdx + 1) % attorneys.length;

const item = $input.first().json;
return [{ json: {
  ...item,
  attorney_name:  attorney.name,
  attorney_email: attorney.email,
  attorney_phone: attorney.phone,
  attorney_index: safeIdx,
} }];

// Composes the acknowledgment SMS to the new lead.
// Personalises with first name when available.
// The TCPA STOP instruction is included here; the Bar-Compliance Guardrail
// detects it and will not append a duplicate.

const item        = $input.first().json;
const FIRM_NAME   = $vars.FIRM_NAME;
const BOOKING_URL = $vars.FIRM_BOOKING_URL;

if (!item.lead_phone) {
  // No phone number — SMS branch will skip gracefully at the compliance check.
  // The email confirmation and attorney alert still fire on their parallel branches.
  return [{ json: {
    ...item,
    channel:      'sms',
    recipient:    '',
    message:      '',
    template_id:  'PAC-19',
    matter_id:    '',
    _skip_reason: 'no_phone',
  } }];
}

const rawFirst  = (item.lead_name || '').split(' ')[0];
const firstName = rawFirst && rawFirst !== 'Prospect' ? rawFirst : '';
const greeting  = firstName ? 'Hi ' + firstName : 'Hi';

const smsText = greeting + ', this is ' + FIRM_NAME + '. We received your inquiry and will be in touch shortly. Book a free consult: ' + BOOKING_URL + ' — Reply STOP to opt out.';

return [{ json: {
  ...item,
  channel:     'sms',
  recipient:   item.lead_phone,
  message:     smsText,
  template_id: 'PAC-19',
  matter_id:   '',
} }];

